import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"黑王冠奇物","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/黑王冠/黑王冠奇物.md","filePath":"4.资源分区/1.血统与训练/3.心智类/黑王冠/黑王冠奇物.md"}'),s={name:"4.资源分区/1.血统与训练/3.心智类/黑王冠/黑王冠奇物.md"};function o(d,b,D,_,l,P){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"黑王冠奇物",tabindex:"-1"},[t("黑王冠奇物 "),r("a",{class:"header-anchor",href:"#黑王冠奇物","aria-label":'Permalink to "黑王冠奇物"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="黑王冠奇物-1" tabindex="-1">黑王冠奇物 <a class="header-anchor" href="#黑王冠奇物-1" aria-label="Permalink to &quot;黑王冠奇物&quot;">​</a></h1><p>黑王冠下属资源——奇物</p><p>莲瓣<br> D+500</p><p>[浮于水面的花瓣指向东方，隐隐昭示着提卡兹解决困境的方向。<br> 然而猎手所能见到的，只有石钵中的清水。他饮尽清水，继续向山脉深处进发......雨过天晴，石钵已重新盈满清水，花瓣悬浮，等待着下一位访客。]</p><p>[前路难行]<br> 现在，每场影片开始时，你获得一个专门的支线任务，该任务往往会以一个高一级的敌人或是复数的同级敌人作为结尾。<br> 每场影片你都必须完成这个支线任务，你可以和其他轮回者合作。<br> 如果有任一场影片你未能完成其中的任务，那么立刻失去这件奇物。</p><p>在完成俩次该支线任务之后，该奇物升级为[托生莲座]</p><p>【托生莲座】<br> [无底却不漏，踏青火以行山泽，渡四方来客，惟解脱者可行舟]</p><p>你现在具有C级的传送移动。<br> 你的基础移速上升决心上的传奇属性*10M。<br> 你的攻击检定获得9加骰。</p><p>[了悟]<br> 现在，每场影片开始时，你获得一个专门的支线任务，该任务往往会以一个高一级的敌人或是复数的同级敌人作为结尾。<br> 每场影片你都必须完成这个支线任务，你可以和其他轮回者合作。<br> 如果有任一场影片你未能完成其中的任务，那么立刻失去这件奇物。</p><p>在完成俩次该任务后，该道具升级为[阿纳萨羯磨]</p><p>【阿纳萨羯磨】<br> [他的心性已变，他的利剑已碎，但身上的结晶无时无刻不在提醒着他，修行尚未结束]</p><p>你现在具有C级的传送移动。<br> 你的基础移速上升决心上的传奇属性*10M。<br> 你的攻击检定获得9加骰。</p><p>在这个阶段，你不在额外获得支线任务。</p><p>死仇时代的恨意<br> D+500<br> 【死仇时代的恨意】<br> “我的父亲被食腐者带走，妹妹被血魔咬死，妈妈带着我逃了出来，我绝不会向萨卡兹妥协，就算要忏悔，也要等到他们全部消失”<br> “不是因为我恨他，而是因为他该死”<br> 鲜血浸润大地，仇恨纠结缠绕，死亡如影随形，愤怒永不停歇。<br> 你的武器伤害提升2点。<br> 当你被攻击时，你会失去2点任意防御，优先从仍有的防御扣除，该效果不会被抵消破防抵消<br> 此外，影片结束时，若你在这一影片中亲手杀死了至少一个同级别单位，你的武器伤害提升耐力属性上的传奇属性*1点，最多以此法成长2次。</p><p>血税之谜<br> D+500<br> “杜卡雷终究失败了，他挺身而出，仍没能阻止自己的兄弟丹索，殷红的锁链于是拴住了大地上的一切生灵。所以如今我们每走一步都会留下一道血的印痕，这血税就是为了还我们那时凭空欠下的债。”</p><p>【血魔】：即使在经常被妖魔化的萨卡兹中，血魔也是最恶名远扬的一支。<br> 它们在黑夜中穿行，以他人的血液为食，杀人如麻，无恶不作......诸如此类。</p><p>现在，你的本源支流【御血术】可以同时对源石能起效，并且在第一次生效之后，你获得耐力上的传奇属性*1点吸血，持续一场景。</p><p>——————————</p><p>预示之谜<br> D+500<br> “摩迩那剜去了自己的独眼，又请巫妖将自己放逐，试图让那偶尔瞥见的景象永久作废。自那以后，新降生的独眼巨人逐渐开始和其他萨卡兹一样，生有双眼。但那预言有人记录了下来，于是仍然应验。”</p><p>【独眼巨人】：关于独眼巨人的传说大抵是真实的。他们能够预见未来，以及，他们所预见的都是厄运。</p><p>【预示之谜】：有的宏大预言会贯穿萨卡兹整个族群的一段漫长历史，甚至促使历史向预言本身收束，因而独眼巨人即使在萨卡兹各族群之内也印象可怖。</p><p>并且此时你可以知晓敏感范围内是否存在敌意单位。知晓剧本内一个名词指向的目标的大致方位（在某个方向、某个地区），但时间上会有误差。这是一个D级信息来源的预知效果。<br> 在携带该奇物经历1场影片之后，你本源支流中的【终局战术】生效时，解析的信息上升2个。<br> ——————————</p><p>盲目</p><p>C+1000</p><p>他们是否还保留着萨卡兹王庭的建制，是否还有王庭之主，如今无人能够确定。众人所能追溯的最后记忆，停留在某位独眼巨人摘下头顶黑色王冠的那一刻。<br> 在上一级的效果基础上，新增【预言】和【盲目】。</p><p>【预言】：<br> 当你携带该奇物经过一场影片之后，你本源支流中的【终局战术】生效时，解析的信息上升2个。<br> 并且此时你可以知晓剧本内一个名词指向的目标的所在位置（某个建筑、某个势力），时间上的误差在不超过一周。这是一个B级信息来源的预知能力。</p><p>【盲目】：<br> 现在当你的本源支流【终局战术】生效时，对方所受到的【劣化1】升级为【劣化2】。<br> ——————————</p><p>预言显像<br> 无法购买</p><p>【预言】<br> 你一定听说过这样一段文字：“我见你，头顶黑冠，将千万生灵，熬成回忆......”</p><p>你的源石能上限增加3点。<br> 在接下来的2场影片中，你都会遇到一名被标记为“终曲和声”的敌人，与他的战斗必定为高一级战斗，如果你在某场影片中没有击败这名敌人，那么这个奇物立刻失去且不再能购买。<br> 如果你在2场影片中都战胜了敌人，那么该奇物升级为【终结的骨架】。<br> ————————————</p><p>终结的骨架<br> 由预言显像逐升<br> 无法购买</p><p>【绝望】<br> “您一定能活下来的，请……相信……呜，呜呜呜……”<br> 到处是天灾，到处是战争。当救助本身都阻止不了死亡，所有医疗行为都只是仇恨的帮凶时，阿米娅只能徒劳且机械地“挽救生命”——这是她唯一能做的事。</p><p>你的意志池上限增加2点，你的源石能上限增加15点。<br> 携带该奇物的时候，你的攻击检定常驻减少2DP，每一轮开始时，你必须使用2AP转化一个迅捷动作，你仍然可以将其保留到回合外，作为反射动作调用。<br> 在携带该奇物经过3场影片，并且在这三场影片之中都获胜了一场高一级战斗之后，你可以在主神空间中，消耗1XP为这个奇物购买1份构想用于喂养它，若你如此做，则将该奇物升级为【终结的躯体】。<br> ————————</p><p>【终结的躯体】<br> 由终结的骨架逐升<br> 无法购买</p><p>【拯救】<br> “请在这里睡一会吧，等找到矿石病的解药，您就能健康地醒来了。”<br> 阿米娅怀着悲伤看着眼前被封入“茧”中的人，他的一切在此定格，这样，他就再也不会疼痛，源石也不会夺走他的生命了。阿米娅不愿意去盲目使用这突然觉醒的力量，可现在......没有更好的选择了。</p><p>你的意志池上限增加10点，你的源石能上限增加15点。<br> 携带该奇物的时候，你的攻击检定常驻减少4DP，每一轮开始时，你必须使用2AP转化一个迅捷动作，你仍然可以将其保留到回合外，作为反射动作调用，并且当你受到攻击时，你选择当前仍然保有的一种防御，那种防御上受到2DP减值。<br> 在携带该奇物经过3场影片，并且在这三场影片之中都获胜了一场高一级战斗之后，你可以在主神空间中，消耗2XP为这个奇物购买2份构想用于喂养它，若你如此做，则将该奇物升级为【终结的实相】<br> ————————————————</p><p>【终结的实相】<br> 由终结的躯体逐升<br> 无法购买</p><p>【停止】<br> “等你们醒来时，就不会再有苦难了，而那之前的痛苦，我会背负。”<br> 随着一切被封入“茧”中，时间在这里只作用于阿米娅一人，她会去寻找一切病源的解药——无论是生理的，还是心理的，她都想要治愈。在那之前，将是一场绝对孤独且几无尽头的长旅。阿米娅已经出发了。</p><p>你的意志池上限增加12点，你的源石能上限增加30点.<br> 携带该奇物的时候，你的攻击检定常驻减少4DP，战斗开始时，你自动消耗2AP转化一个迅捷动作，并且当你受到攻击时，你选择当前仍然保有的一种防御，那种防御上受到2DP减值，如果你的攻击可以额外选择敌人，那么减少一个可选择敌人。<br> ————————</p><p>演出用香水<br> D+1000</p><p>【幻香】：剧团演员们上台前会喷一些在身上，这种稳定且芬芳的香气能为演员持续舒缓压力，至少，表面上，看上去是这样的。</p><p>现在你的伤势自动稳定，并且当你的本源支流【无惧疼痛】生效时，你获得的快速医疗增加耐力上的传奇属性*1点，附带传奇耐力*12的医疗点。<br> ————————</p><p>热水壶<br> D+1000<br> “我带来了生命，与希望”</p><p>这是一个神奇的水壶，尽管不会从中涌出水来，但是用它冲泡的泡面实属一绝，而且温度会自适应在能泡开泡面而不会烫伤的程度，因为理论上你可以在嘴里泡泡面<br> ——当然，不推荐</p><p>目标生命：<br> 你现在的伤势会自动稳定，不会恶化。</p><p>前路希望：<br> 在每场同级战斗结束后，你都会获得仅能用于购买黑王冠下属物品的1XP，每场影片最多以此法获得3XP。</p><p>指挥等级：<br> 影片结束时，若你这场影片中经历了一次同级别和一次高一级战斗且获胜，则获得1意志力上限。</p><p>————————</p><p>海嗣神经模拟系统<br> D+1000<br> 在影片结束时，如果你经历了一次同级战斗并且胜出,检测你当前的意志力池，如果你的意志力池低于30%，那么获得【排异反应】，如果意志力池大于70%，获得【启示】，一影片最多获得一次,不能重复获得同一种【排异反应】或【启示】<br> 【启示】<br> [乌萨斯的怒号]<br> “冬雷轰鸣，那是乌萨斯胜利的呼喊。”<br> 在战斗第一回合时，你额外投掷一枚十面骰，将其出目加入你的先攻，并且在下一轮开始时失去这部分先攻，在本轮中，你的攻击获得【融毁5】，在攻击先攻低于你的敌人时，你的攻击检定额外上升2DP。<br> [大炎的沧桑]<br> “岁月如梭，织就大炎锦绣山河。”<br> 一轮一次，你的能量消耗减少2点（最低为1），每轮开始时，获得1点临时生命，持续一轮。<br> [哥伦比亚的创想]<br> “这片大地仍被过往束缚，哥伦比亚已在创造未来。”<br> 下一次战斗结束后，你获得6点仅能用于购买黑王冠下属物品的xp。<br> [萨米的坚韧]<br> “只要自然一息尚存，萨米的血脉便不会断绝。”<br> 你获得快速医疗1（12医疗点），升级至快速医疗2（24医疗点），替换之前的效果。<br> [维多利亚的荣耀]<br> “历史见证了维多利亚的崛起，它仍将见证。”<br> 在面对攻击时，获得25%概率生效的2DR/-和2全能量抗性<br> [莱塔尼亚的优雅]<br> “如果心中没有艺术与情感，我们与磐蟹又有什么不同？”<br> 获得4DR/法破。<br> [萨尔贡的慷慨]<br> “黄金之城的财富落入风沙，萨尔贡就此闪闪发亮。”<br> 立刻获得6点XP，仅能用于购买黑王冠下属物品。</p><p>【排异反应】<br> [造血障碍]<br> 血细胞凋亡加速，骨髓造血机能受抑制<br> 当你的完好不为满时，你每轮结束时都会受到1点不可减免的严重伤害，此时你的攻击检定额外获得决心上的传奇属性*2点增强加值。<br> [专注失调]<br> 感知机能减弱，丧失协调性，应激机制失控<br> 每轮开始时，自动消耗2点能量，你在本轮中的下一次使用能量的攻击额外获得【9加骰】，并且这次攻击的伤害类型可以在精神和力场中选择。<br> [神经退行]<br> 大脑神经元萎缩，反应迟缓，意识游离<br> 战斗开始的第一轮结束时，失去剩余的全部AP，每失去1点，获得1点DR/法破，最多获得5DR/法破。<br> [血肉畸变]<br> 体外细胞进入循环系统，电信号传递异位，体组织全面收缩<br> 战斗第一轮开始时，受到2点不可避免的严重伤害，随后在本场战斗中，你的基础移速上升决心上的传奇属性*10M。<br> ——————————</p><p>戈渎不语<br> D+500<br> 占据下肢-躯干位<br> 他站在卡兹戴尔的最高处，自此化为石雕。神民霸主们见到黑冠后退却，萨卡兹们见到黑冠后喜悦。这名为“魔王”的奇观存在了很久，直至有一天，萨卡兹们忘却了魔王，亲手将它从塔顶上推下。<br> 你获得基于任一防御的【防弹】【防能量】（获得时选择防御类型），且该防御类型至少需要有5点。<br> 但是你每受到一次攻击/每轮结束时，你在这个场景中的对应防御就下降1点，最多减少3点，如果此时你的选择防御已经因为某种原因降低到了0，则受到1点不可避免的严重伤害。<br> 你额外获得决心上的传奇属性*1+1点你选择的对应防御。<br> ————————</p><p>霸迩萨狂言<br> D+500<br> 占据下肢-躯干位<br> 熔岩顺从地跟随着霸迩萨的军队在大地上蔓延。他们不在乎神民霸主，也不在乎其他萨卡兹。这片大地是炎魔的大地，不需要容下别人，而作为炎魔的王，霸迩萨也无法容忍王冠落在别人的脑袋上。<br> 以一个自由动作消耗2能量启用，在当前场景你获得5点【融毁】，但是你每轮结束/每次攻击时，你的攻击DP都会减少2点，最多十点，你每受到2点DP上的减值，你就可以将3点破甲转换为等量破魔<br> 。<br> ————————</p><p>诸王的冠冕<br> C+1000<br> 占据头盔位<br> 无名的诸王啊，纵使王国毁灭，仍愿您护佑伊比利亚。<br> 携带者的决心检定上升力量上的传奇属性*2点，同时获得<br> 如果你同时携带额外的三件国王收藏品，那么提升至力量上的传奇属性*6点，同时获得1点异常点治疗（24医疗点）。<br> ————————</p><p>国王的新枪<br> D+500<br> 占据手腕位<br> 绝境下的美好祈愿能带给人希望，即使那并不是真相。<br> 携带者获得决心上的传奇属性*2点高速，此奇物提供的高速在破除全部防御之后，会转为等额的攻击高速加值。<br> 你的先攻提升4点。<br> ——————————</p><p>国王的铠甲<br> C+1000<br> 占据斗篷位<br> 王宫的大门前、广场上，曾摆放着那么多金色的展柜，四方珍品尽供欣赏。而现在，仅仅是回想那个场面就会让人受伤。<br> 携带者获得决心上的传奇属性*1点临时生命，由该奇物提供的临时生命，会每轮一次的刷新。<br> 携带者额外获得1点临时生命。<br> ——————————</p><p>国王的延伸<br> C+1000<br> 占据腰带位<br> 成长，认清现实，用坚韧与笃定武装自己，用包容与慈恩武装朋友。<br> 携带者获得3点快速医疗（医疗点36），<br> 此外，如果携带者具有本源支流【快速反应】，那么在本源支流满足生效条件时，立刻获得2AP，只能用于黑王冠下属技艺的使用，之后在进行正常的判定。<br> ——————————</p><p>魔王的床榻<br> C+1000<br> 占据下肢-躯干位<br> 身居此位者，安睡即为永眠。<br> 携带者获得决心上的传奇属性*1点闪避防御上的附加成功。<br> 额外获得传奇属性*2点闪避防御。<br> ————————</p><p>魔王的旗帜<br> C+1000<br> 占据斗篷位<br> 身居此位者，抗争便会陨落。<br> 携带者获得决心上的传奇属性*1枚先攻骰。<br> 携带者获得决心上的传奇属性*2点高速，由此奇物提供的高速可以在破除全部防御之后转化为等量加值。<br> ——————————</p><p>魔王的冠冕<br> C+1000<br> 占据头盔位<br> 身居此位者，兴盛仅是泡影。<br> 携带者获得决心上的传奇属性*1点生命值，此外，在决心检定上获得2DP器械加值。<br> 当同时携带另外俩件魔王收藏品时，这个数值提升至决心上的传奇属性*3点。<br> ————————-</p><p>。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',62)])])}const h=p(s,[["render",o]]);export{c as __pageData,h as default};
